body.script:
  const client = createClient(
    "https://uebguqrxirqyjhxtyuef.supabase.co",
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InVlYmd1cXJ4aXJxeWpoeHR5dWVmIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODQ2NTc3MDYsImV4cCI6MjEwMDIzMzcwNn0.JkWPHlDbv7UbFoJDCYbj-njSoGDq7_Vg02R-HmM4M6s"
  );

    async function loadProductsFromDB() {
      const { data, error } = await client
        .from("PRODUCTS_JSON")
        .select("product_json")
        .eq("product_status", "ACTIVE")
        .maybeSingle();

      if (error) {
        console.error("Error loading JSON:", error);
        return;
      }

      const products = data.product_json.products;
      loadProductsIntoUI(products);
    }

    function loadProductsIntoUI(products) {
      const container = document.getElementById("productgroup");
      container.innerHTML = "";

      products.forEach(p => {
        container.innerHTML += `


            

${p.details.name}

${p.details.description}

Fabric: ${p.details.fabric}

Offer: ₹${p.pricing.offer_price} ₹${p.pricing.price}

Colors: ${p.colors.join(", ")}

Sizes: 
              S:${p.sizes.S}, 
              M:${p.sizes.M}, 
              L:${p.sizes.L}, 
              XL:${p.sizes.XL}, 
              XXL:${p.sizes.XXL}
            
          
        `;
      });
    }
